using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    // Build the graph
    vector<vector<long long>> graph(c + 1);
    for (auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    // For each node, keep track of its current parent in the DSU
    vector<long long> parent(c + 1, 0);
    // For each node, keep track of the minimum id in its component
    vector<long long> min_id(c + 1, 0);

    // Initialize DSU
    for (long long i = 1; i <= c; ++i) {
        parent[i] = i;
        min_id[i] = i;
    }

    // Function to find the root of a node
    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    // Function to union two nodes
    void union_nodes(long long x, long long y) {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x != root_y) {
            parent[root_y] = root_x;
            min_id[root_x] = min(min_id[root_x], min_id[root_y]);
        }
    }

    // Build the DSU structure based on the graph
    for (long long i = 1; i <= c; ++i) {
        for (auto& neighbor : graph[i]) {
            if (i < neighbor) {
                union_nodes(i, neighbor);
            }
        }
    }

    // Keep track of which nodes are online
    vector<bool> online(c + 1, true);

    vector<long long> result;

    for (auto& query : queries) {
        long long type = query[0];
        long long x = query[1];

        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                long long root = find(x);
                long long min_online = -1;
                for (long long i = 1; i <= c; ++i) {
                    if (online[i] && find(i) == root) {
                        if (min_online == -1 || i < min_online) {
                            min_online = i;
                        }
                    }
                }
                result.push_back(min_online);
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}

